#include <vector>
#include <algorithm>
#include <numeric>
#include <climits>

using namespace std;

struct DSU {
    vector<int> parent;
    vector<int> rank;

    DSU(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        iota(parent.begin(), parent.end(), 0);
    }

    int find(int u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    bool unite(int u, int v) {
        int pu = find(u);
        int pv = find(v);
        if (pu == pv) return false;
        if (rank[pu] < rank[pv]) {
            parent[pu] = pv;
        } else if (rank[pu] > rank[pv]) {
            parent[pv] = pu;
        } else {
            parent[pv] = pu;
            rank[pu]++;
        }
        return true;
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;
    for (const auto& e : edges) {
        if (e[3] == 1) {
            must_edges.push_back(e);
        } else {
            optional_edges.push_back(e);
        }
    }

    DSU dsu(n);
    int components = n;
    for (const auto& e : must_edges) {
        if (dsu.unite(e[0], e[1])) {
            components--;
        }
    }

    if (components == 1) {
        long long min_strength = LLONG_MAX;
        for (const auto& e : must_edges) {
            min_strength = min(min_strength, e[2]);
        }
        return min_strength;
    }

    sort(optional_edges.begin(), optional_edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] > b[2];
    });

    vector<vector<long long>> upgraded_edges;
    for (const auto& e : optional_edges) {
        upgraded_edges.push_back({e[0], e[1], e[2] * 2, e[3]});
    }

    long long left = 0;
    long long right = 1e18;
    long long answer = -1;

    while (left <= right) {
        long long mid = left + (right - left) / 2;
        DSU temp_dsu(n);
        int temp_components = n;
        int used_k = 0;

        for (const auto& e : must_edges) {
            if (temp_dsu.unite(e[0], e[1])) {
                temp_components--;
            }
        }

        for (const auto& e : optional_edges) {
            if (e[2] >= mid) {
                if (temp_dsu.unite(e[0], e[1])) {
                    temp_components--;
                }
            } else if (e[2] * 2 >= mid && used_k < k) {
                if (temp_dsu.unite(e[0], e[1])) {
                    temp_components--;
                    used_k++;
                }
            }
        }

        if (temp_components == 1) {
            answer = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return answer;
}

