use std::cmp::{min, max};

struct DSU {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl DSU {
    fn new(n: usize) -> Self {
        DSU {
            parent: (0..n).collect(),
            rank: vec![0; n],
        }
    }

    fn find(&mut self, u: usize) -> usize {
        if self.parent[u] != u {
            self.parent[u] = self.find(self.parent[u]);
        }
        self.parent[u]
    }

    fn unite(&mut self, u: usize, v: usize) -> bool {
        let pu = self.find(u);
        let pv = self.find(v);
        if pu == pv {
            return false;
        }
        if self.rank[pu] < self.rank[pv] {
            self.parent[pu] = pv;
        } else if self.rank[pu] > self.rank[pv] {
            self.parent[pv] = pu;
        } else {
            self.parent[pv] = pu;
            self.rank[pu] += 1;
        }
        true
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let k = k as usize;
    let mut must_edges = Vec::new();
    let mut optional_edges = Vec::new();

    for e in edges {
        if e[3] == 1 {
            must_edges.push(e);
        } else {
            optional_edges.push(e);
        }
    }

    let mut dsu = DSU::new(n);
    let mut components = n;
    for e in &must_edges {
        if dsu.unite(e[0] as usize, e[1] as usize) {
            components -= 1;
        }
    }

    if components == 1 {
        let mut min_strength = i64::MAX;
        for e in must_edges {
            min_strength = min(min_strength, e[2]);
        }
        return min_strength;
    }

    optional_edges.sort_by(|a, b| b[2].cmp(&a[2]));

    let mut left = 0;
    let mut right = 1e18 as i64;
    let mut answer = -1;

    while left <= right {
        let mid = left + (right - left) / 2;
        let mut temp_dsu = DSU::new(n);
        let mut temp_components = n;
        let mut used_k = 0;

        for e in &must_edges {
            if temp_dsu.unite(e[0] as usize, e[1] as usize) {
                temp_components -= 1;
            }
        }

        for e in &optional_edges {
            if e[2] >= mid {
                if temp_dsu.unite(e[0] as usize, e[1] as usize) {
                    temp_components -= 1;
